from flask import Flask, request, jsonify, abort
import hmac, hashlib, os

app = Flask(__name__)
CALLBACK_API_KEY = os.environ['VC_CALLBACK_API_KEY']

@app.route('/api/vc/presentation-callback', methods=['POST'])
def presentation_callback():
    # Validate the callback API key (shared secret set in the presentation request)
    provided_key = request.headers.get('api-key', '')
    if not hmac.compare_digest(provided_key, CALLBACK_API_KEY):
        abort(401)

    data = request.get_json(force=True)
    status = data.get('requestStatus')
    state  = data.get('state')

    if status == 'presentation_verified':
        creds = data.get('verifiedCredentialsData', [])
        for cred in creds:
            if 'VerifiedEmployee' in cred.get('type', []):
                claims = cred.get('claims', {})
                revocation = cred.get('credentialState', {}).get('revocationStatus')
                if revocation != 'VALID':
                    # Credential revoked — deny access
                    return jsonify({'status': 'denied', 'reason': 'credential_revoked'}), 200
                # Persist the verified session (map state -> claims)
                store_verified_session(state, claims)

    elif status == 'presentation_error':
        error = data.get('error', {}).get('message', 'unknown error')
        log_verification_failure(state, error)

    return jsonify({'status': 'ok'}), 200

